BEGIN;

CREATE TEMP TABLE tmp_discover_projection_stage (
  age_band_id TEXT NOT NULL,
  age_band_label TEXT NOT NULL,
  min_months INTEGER NOT NULL,
  max_months INTEGER NOT NULL,
  age_band_is_active BOOLEAN NOT NULL,
  stage1_wrapper_ux_slug TEXT NOT NULL,
  stage1_wrapper_ux_label TEXT NOT NULL,
  stage1_wrapper_rank_in_band INTEGER NOT NULL,
  stage1_mapping_is_active BOOLEAN NOT NULL,
  development_need_slug TEXT NOT NULL,
  development_need_canonical_name TEXT NOT NULL,
  stage1_why_it_matters_ux_description TEXT,
  audience_lens TEXT,
  stage2_category_type_slug TEXT NOT NULL,
  stage2_category_type_label TEXT NOT NULL,
  stage2_category_type_name TEXT NOT NULL,
  stage2_play_ideas_rank INTEGER NOT NULL,
  stage2_play_idea_mapping_rationale TEXT,
  category_audience_lens TEXT
) ON COMMIT DROP;

INSERT INTO tmp_discover_projection_stage (
  age_band_id,
  age_band_label,
  min_months,
  max_months,
  age_band_is_active,
  stage1_wrapper_ux_slug,
  stage1_wrapper_ux_label,
  stage1_wrapper_rank_in_band,
  stage1_mapping_is_active,
  development_need_slug,
  development_need_canonical_name,
  stage1_why_it_matters_ux_description,
  audience_lens,
  stage2_category_type_slug,
  stage2_category_type_label,
  stage2_category_type_name,
  stage2_play_ideas_rank,
  stage2_play_idea_mapping_rationale,
  category_audience_lens
)
VALUES
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_words_pointing','I’m finding my words',1,true,'need_words_gestures','Finding words everywhere','Your toddler may be pointing, naming familiar things or waiting for you to add the word. Books, songs and everyday object hunts turn these little moments into conversation, helping them connect what they understand with what they are starting to say.','for_your_child','cat_first_word_picture_books','First-word books to point at','First Word Picture Books',1,'Your toddler may point, name or wait for you to say the word. First-word books give easy chances to repeat, pause and add language around animals, body parts and everyday objects, without making speech feel like a test during ordinary family moments.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_words_pointing','I’m finding my words',1,true,'need_words_gestures','Finding words everywhere','Your toddler may be pointing, naming familiar things or waiting for you to add the word. Books, songs and everyday object hunts turn these little moments into conversation, helping them connect what they understand with what they are starting to say.','for_your_child','cat_body_part_books_games','Body-part books and naming games','Body Part Books Games',2,'As body-part pointing starts to appear, dressing, bath time and simple books can become easy naming moments. Asking for eyes, nose or tummy gives your toddler a clear word-to-action link and lets them show understanding before speech is fully clear.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_words_pointing','I’m finding my words',1,true,'need_words_gestures','Finding words everywhere','Your toddler may be pointing, naming familiar things or waiting for you to add the word. Books, songs and everyday object hunts turn these little moments into conversation, helping them connect what they understand with what they are starting to say.','for_your_child','cat_naming_walks','Words on walks and little hunts','Naming Walks',3,'A buggy trip, walk to the park or lap around the house can become a tiny naming game. Pointing out buses, shoes, dogs and doors helps your toddler connect real things with words, especially when you pause and let them point or answer.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_words_pointing','I’m finding my words',1,true,'need_words_gestures','Finding words everywhere','Your toddler may be pointing, naming familiar things or waiting for you to add the word. Books, songs and everyday object hunts turn these little moments into conversation, helping them connect what they understand with what they are starting to say.','for_your_child','cat_songs_action_games','Songs with actions to copy','Songs Action Games',4,'Songs with actions give your toddler a way to join in before every word is clear. Clapping, pointing, nodding or doing the same action again can support listening, gestures, turn-taking and memory, without making language feel like a lesson in everyday family life.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_pretend_copying','I’m copying everyday life',2,true,'need_pretend_copying','Copying everyday life','Your toddler may copy feeding a teddy, stirring a bowl or carrying a little bag. Pretend play gives those watched routines a safe, funny place to practise, while building language, memory, care and early social understanding through scenes they already recognise.','for_your_child','cat_doll_soft_toy_care','A doll or teddy to care for','Doll Soft Toy Care',1,'Your toddler may copy feeding, wiping or cuddling a soft toy after seeing those routines at home. Doll and teddy care gives them a safe way to practise language, sequencing and social understanding, while making everyday care feel funny and familiar.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_pretend_copying','I’m copying everyday life',2,true,'need_pretend_copying','Copying everyday life','Your toddler may copy feeding a teddy, stirring a bowl or carrying a little bag. Pretend play gives those watched routines a safe, funny place to practise, while building language, memory, care and early social understanding through scenes they already recognise.','for_your_child','cat_toy_cups_spoons','Pretend cups, spoons and food','Toy Cups Spoons',2,'Pretend cups, spoons and food let your toddler copy the routines they watch every day. They can stir, offer a teddy a drink or put food on a plate, giving them a playful way to connect objects, actions and early words.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_pretend_copying','I’m copying everyday life',2,true,'need_pretend_copying','Copying everyday life','Your toddler may copy feeding a teddy, stirring a bowl or carrying a little bag. Pretend play gives those watched routines a safe, funny place to practise, while building language, memory, care and early social understanding through scenes they already recognise.','for_your_child','cat_play_kitchen_household_props','A little kitchen or household props','Play Kitchen Household Props',3,'A small kitchen, pan, whisk or safe household prop can make imitation feel irresistible. Pretend chores and cooking help your toddler practise memory, language and social roles, especially when you join in briefly and give words to what they are doing.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_pretend_copying','I’m copying everyday life',2,true,'need_pretend_copying','Copying everyday life','Your toddler may copy feeding a teddy, stirring a bowl or carrying a little bag. Pretend play gives those watched routines a safe, funny place to practise, while building language, memory, care and early social understanding through scenes they already recognise.','for_your_child','cat_toddler_bag_carry','A little bag for pretend errands','Toddler Bag Carry',4,'A small bag, basket or pouch lets your toddler copy shopping, nursery drop-off or little errands at home. Carrying objects from one place to another gives pretend play a clear job, while supporting memory, coordination and practical independence in a playful way.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_pretend_copying','I’m copying everyday life',2,true,'need_pretend_copying','Copying everyday life','Your toddler may copy feeding a teddy, stirring a bowl or carrying a little bag. Pretend play gives those watched routines a safe, funny place to practise, while building language, memory, care and early social understanding through scenes they already recognise.','for_your_child','cat_doctor_visit_books','Doctor and care stories','Doctor Visit Books',5,'Simple doctor, dentist or care books can make unfamiliar routines easier to talk about. Naming the bag, thermometer or waiting room gives your toddler language for real moments, while pretend check-ups with a teddy keep the practice low-pressure before real appointments.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_busy_hands','My hands are busy now',3,true,'need_two_handed_control','Busy little hands','Your toddler may keep turning, opening, stacking and posting things to see what happens. These small hand challenges help them practise control, focus and problem-solving, especially when they can repeat the same satisfying action in their own way and see a clear result.','for_your_child','cat_shape_sorters_puzzles','Shape sorters and first puzzles','Shape Sorters Puzzles',1,'A shape sorter or chunky puzzle gives your toddler a clear problem to work through: turn it, test it, try again. The value is in the experimenting, not getting it right quickly, because that practice supports focus, hand control and early problem-solving.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_busy_hands','My hands are busy now',3,true,'need_two_handed_control','Busy little hands','Your toddler may keep turning, opening, stacking and posting things to see what happens. These small hand challenges help them practise control, focus and problem-solving, especially when they can repeat the same satisfying action in their own way and see a clear result.','for_your_child','cat_stacking_pegboard','Pegboards and stacking towers','Stacking Pegboard',2,'Stacking pegs, cups or blocks gives your toddler a satisfying reason to use both hands together. They can place, wobble, knock down and rebuild, practising control, balance, attention and persistence through a game they often want to repeat in everyday family life.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_busy_hands','My hands are busy now',3,true,'need_two_handed_control','Busy little hands','Your toddler may keep turning, opening, stacking and posting things to see what happens. These small hand challenges help them practise control, focus and problem-solving, especially when they can repeat the same satisfying action in their own way and see a clear result.','for_your_child','cat_matching_animals_figures','Chunky animals to match and name','Matching Animals Figures',3,'Chunky animals, figures or matching pictures give your toddler something to hold while you name, sort and compare. Putting the dog with the dog or making the cow say moo can turn matching into language, memory and pretend play in everyday family life.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_busy_hands','My hands are busy now',3,true,'need_two_handed_control','Busy little hands','Your toddler may keep turning, opening, stacking and posting things to see what happens. These small hand challenges help them practise control, focus and problem-solving, especially when they can repeat the same satisfying action in their own way and see a clear result.','for_your_child','cat_posting_drop_boxes','Posting boxes and hidey slots','Posting Drop Boxes',4,'Posting, dropping and tucking objects into a box can hold a toddler’s attention because the action is simple and satisfying. It helps them practise hand control, object permanence and problem-solving, especially when they can open the box and do it again.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_busy_hands','My hands are busy now',3,true,'need_two_handed_control','Busy little hands','Your toddler may keep turning, opening, stacking and posting things to see what happens. These small hand challenges help them practise control, focus and problem-solving, especially when they can repeat the same satisfying action in their own way and see a clear result.','for_your_child','cat_latch_busy_boards','Latches, lids and busy boards','Latch Busy Boards',5,'Latches, lids, switches and flaps can be fascinating at this stage. A toddler-safe busy board or box gives those urges a safer place to practise opening, closing and figuring things out, while building hand strength, focus and persistence in everyday family life.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_move_climb','I’m moving with purpose',4,true,'need_gross_motor','Moving with purpose','Your toddler may be quicker on their feet, more eager to climb and ready to chase a ball across the room. Safe movement games help them practise balance, coordination and confidence, while giving their new energy somewhere useful to go.','for_your_child','cat_soft_graspable_balls','Soft balls to kick and chase','Soft Graspable Balls',1,'A soft ball gives your toddler a simple reason to run, stop, kick, roll and chase. Passing it back and forth also brings social play into movement, helping them practise coordination, balance, attention and taking turns in a very physical way.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_move_climb','I’m moving with purpose',4,true,'need_gross_motor','Moving with purpose','Your toddler may be quicker on their feet, more eager to climb and ready to chase a ball across the room. Safe movement games help them practise balance, coordination and confidence, while giving their new energy somewhere useful to go.','for_your_child','cat_pull_push_toys','Push-and-pull toys for walking','Pull Push Toys',2,'A push or pull toy can turn walking into a job: take it across the room, bring it back, try again. That little purpose helps your toddler practise balance, direction and coordination while making new movement feel playful and useful.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_move_climb','I’m moving with purpose',4,true,'need_gross_motor','Moving with purpose','Your toddler may be quicker on their feet, more eager to climb and ready to chase a ball across the room. Safe movement games help them practise balance, coordination and confidence, while giving their new energy somewhere useful to go.','for_your_child','cat_low_climb_tunnel','Low climbing and crawl-through play','Low Climb Tunnel',3,'If your toddler wants to climb everything, low cushions, tunnels or a supervised soft-play setup can give that energy a safer route. Crawling through, stepping over and climbing down helps them practise coordination, balance and body awareness with you close by.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_move_climb','I’m moving with purpose',4,true,'need_gross_motor','Moving with purpose','Your toddler may be quicker on their feet, more eager to climb and ready to chase a ball across the room. Safe movement games help them practise balance, coordination and confidence, while giving their new energy somewhere useful to go.','for_your_child','cat_music_dance','Dancing games and music','Music Dance',4,'A song with a beat can turn the living room into a movement game. Stomping, spinning, clapping and copying actions help your toddler link rhythm with body control, listening and social play, especially when you join in for a short burst.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_move_climb','I’m moving with purpose',4,true,'need_gross_motor','Moving with purpose','Your toddler may be quicker on their feet, more eager to climb and ready to chase a ball across the room. Safe movement games help them practise balance, coordination and confidence, while giving their new energy somewhere useful to go.','for_your_child','cat_park_swing_walks','Park walks and toddler swings','Park Swing Walks',5,'A short park trip can offer climbing, chasing, swinging and naming without needing a packed activity. Staying close around equipment lets your toddler practise bigger movement and confidence, while outdoor routines also give you easy words to point out together.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_pouring_feeding','I’m learning to feed myself',5,true,'need_self_feeding','Doing more at the table','Your toddler may want to hold the cup, scoop yoghurt or pour water again and again. Mealtime and bath-time practice can build hand control and independence, while calmer setups make spills, mess and trying foods feel easier to manage day to day.','for_both','cat_pouring_jug_cups','Pouring jugs and water cups','Pouring Jug Cups',1,'Pouring water between cups in the bath or at a tray gives your toddler a safe way to practise control. They can tip, fill, spill and try again, learning about movement, volume and cause-and-effect through a very ordinary moment in everyday family life.','for_both'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_pouring_feeding','I’m learning to feed myself',5,true,'need_self_feeding','Doing more at the table','Your toddler may want to hold the cup, scoop yoghurt or pour water again and again. Mealtime and bath-time practice can build hand control and independence, while calmer setups make spills, mess and trying foods feel easier to manage day to day.','for_both','cat_open_cup','Open-cup practice','Open Cup',2,'An open cup asks a lot from a toddler: lift, tilt, pause and put it down. Small amounts of water and a calm setup can make spills feel manageable, while your toddler practises coordination, independence and mouth control in everyday family life.','for_both'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_pouring_feeding','I’m learning to feed myself',5,true,'need_self_feeding','Doing more at the table','Your toddler may want to hold the cup, scoop yoghurt or pour water again and again. Mealtime and bath-time practice can build hand control and independence, while calmer setups make spills, mess and trying foods feel easier to manage day to day.','for_both','cat_first_spoons_bowls','Small spoons and steady bowls','First Spoons Bowls',3,'A small spoon and steady bowl can make self-feeding feel less fiddly. Your toddler may still use fingers, spill or swap hands, but each scoop gives them useful practice in hand control, focus and doing more at the table in everyday family life.','for_both'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_pouring_feeding','I’m learning to feed myself',5,true,'need_self_feeding','Doing more at the table','Your toddler may want to hold the cup, scoop yoghurt or pour water again and again. Mealtime and bath-time practice can build hand control and independence, while calmer setups make spills, mess and trying foods feel easier to manage day to day.','for_both','cat_finger_food_snack_prep','Finger-food and snack prep','Finger Food Snack Prep',4,'As your toddler gets more confident with finger foods, food shape and supervision matter. Safe cutting, softer textures and sitting down to eat help them practise independence while reducing choking risks that become easy to miss in busy family routines.','for_both'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_pouring_feeding','I’m learning to feed myself',5,true,'need_self_feeding','Doing more at the table','Your toddler may want to hold the cup, scoop yoghurt or pour water again and again. Mealtime and bath-time practice can build hand control and independence, while calmer setups make spills, mess and trying foods feel easier to manage day to day.','for_both','cat_mealtime_routine_setup','A calmer mealtime setup','Mealtime Routine Setup',5,'At this stage, meals can swing between independence, mess and refusal. A steadier setup, simple choices and low-pressure language can help your toddler join family meals, practise feeding skills and explore food without every bite becoming a negotiation in everyday family life.','for_both'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_big_feelings','I’m having big feelings',6,true,'need_emotions_self_control','Big feelings, little choices','Your toddler may want to say no, choose for themselves or do things their own way. That push for independence is normal, but it can feel big. Simple choices, songs and comfort routines help them feel understood while practising early self-control.','for_your_child','cat_feelings_faces_books','Feelings and faces books','Feelings Faces Books',1,'Books with clear faces can help your toddler start connecting words with feelings: happy, sad, cross, tired. Naming feelings during quiet moments gives them simple language for later, when emotions arrive quickly and they need help making sense of them.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_big_feelings','I’m having big feelings',6,true,'need_emotions_self_control','Big feelings, little choices','Your toddler may want to say no, choose for themselves or do things their own way. That push for independence is normal, but it can feel big. Simple choices, songs and comfort routines help them feel understood while practising early self-control.','for_your_child','cat_simple_choice_cards','Simple choice cards and cues','Simple Choice Cards',2,'Offering two simple choices can help your toddler feel involved without opening every option. Picture cards, pointing choices or clear cues can support independence, understanding and calmer cooperation, especially around clothes, snacks and getting ready to leave the house in everyday family life.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_big_feelings','I’m having big feelings',6,true,'need_emotions_self_control','Big feelings, little choices','Your toddler may want to say no, choose for themselves or do things their own way. That push for independence is normal, but it can feel big. Simple choices, songs and comfort routines help them feel understood while practising early self-control.','for_your_child','cat_routine_songs','Songs for tricky transitions','Routine Songs',3,'Leaving the park, getting dressed or washing hands can feel easier when the next step is familiar. A short routine song or repeated cue gives your toddler a pattern to recognise, helping them move between moments with less surprise in everyday family life.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_big_feelings','I’m having big feelings',6,true,'need_emotions_self_control','Big feelings, little choices','Your toddler may want to say no, choose for themselves or do things their own way. That push for independence is normal, but it can feel big. Simple choices, songs and comfort routines help them feel understood while practising early self-control.','for_your_child','cat_comfort_toy','A safe comfort object','Comfort Toy',4,'A familiar soft toy or comfort object can help some toddlers settle through travel, childcare or changes in routine. It is not a solution for every feeling, but it can offer a steady, recognisable anchor when the day feels bigger than usual.','for_your_child'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_potty_bathroom','I’m noticing bathroom routines',7,true,'need_toileting_readiness','Noticing bathroom routines','Your toddler may be noticing nappies, toilets, flushing or handwashing, even if potty learning is not ready yet. Simple books, words and bathroom routines can make the idea familiar, while keeping the pace relaxed, practical and child-led over time, without pressure.','for_both','cat_potty','A simple potty to notice','Potty',1,'A simple potty can sit in the bathroom before active training starts, so your toddler can notice, sit briefly or copy routines when interested. The aim is familiarity, not performance, especially if readiness signs are still emerging slowly, in everyday family life.','for_both'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_potty_bathroom','I’m noticing bathroom routines',7,true,'need_toileting_readiness','Noticing bathroom routines','Your toddler may be noticing nappies, toilets, flushing or handwashing, even if potty learning is not ready yet. Simple books, words and bathroom routines can make the idea familiar, while keeping the pace relaxed, practical and child-led over time, without pressure.','for_both','cat_potty_books','Potty and bathroom books','Potty Books',2,'Potty books can give your toddler words for nappies, wees, poos, flushing and handwashing before those routines feel urgent. Reading together keeps the idea calm and familiar, while giving you shared language for later toilet learning, whenever readiness grows in everyday family life.','for_both'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_potty_bathroom','I’m noticing bathroom routines',7,true,'need_toileting_readiness','Noticing bathroom routines','Your toddler may be noticing nappies, toilets, flushing or handwashing, even if potty learning is not ready yet. Simple books, words and bathroom routines can make the idea familiar, while keeping the pace relaxed, practical and child-led over time, without pressure.','for_both','cat_step_stool_bathroom','A bathroom step stool','Step Stool Bathroom',3,'If your toddler wants to reach the sink, a stable bathroom step can make handwashing feel more possible with supervision. It supports practical independence and routine learning, while reminding you to manage taps, water and climbing safely every time in everyday family life.','for_both'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_potty_bathroom','I’m noticing bathroom routines',7,true,'need_toileting_readiness','Noticing bathroom routines','Your toddler may be noticing nappies, toilets, flushing or handwashing, even if potty learning is not ready yet. Simple books, words and bathroom routines can make the idea familiar, while keeping the pace relaxed, practical and child-led over time, without pressure.','for_both','cat_toilet_seat_footrest','Toilet seat and foot support','Toilet Seat Footrest',4,'Some toddlers prefer a toilet seat insert later on, especially if they can sit securely with feet supported. At 19–21 months, this is a gentle readiness option rather than a push, useful when your toddler is already curious in everyday family life.','for_both'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_potty_bathroom','I’m noticing bathroom routines',7,true,'need_toileting_readiness','Noticing bathroom routines','Your toddler may be noticing nappies, toilets, flushing or handwashing, even if potty learning is not ready yet. Simple books, words and bathroom routines can make the idea familiar, while keeping the pace relaxed, practical and child-led over time, without pressure.','for_both','cat_handwashing_routine','Handwashing games and little steps','Handwashing Routine',5,'Handwashing can become a tiny sequence: step up, wet hands, soap, rub, rinse, dry. Turning it into a short game or song helps your toddler practise order, independence and hygiene without needing a big lesson every time in everyday family life.','for_both'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_safer_home','Make exploring safer',8,true,'need_home_safety','A home for a quick explorer','Your toddler may suddenly reach higher, climb faster or copy more adult routines. A simple safety refresh helps the home match their new movement: stairs, cupboards, windows, small objects, bath time and food prep all need another look at this stage.','for_you','cat_safety_gates','Safety gates for stairs','Safety Gates',1,'As climbing and speed increase, stairs may need another look. Correctly fitted safety gates can help manage access while your toddler is still learning how to move safely, but they sit alongside supervision and clear household routines with you close by.','for_you'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_safer_home','Make exploring safer',8,true,'need_home_safety','A home for a quick explorer','Your toddler may suddenly reach higher, climb faster or copy more adult routines. A simple safety refresh helps the home match their new movement: stairs, cupboards, windows, small objects, bath time and food prep all need another look at this stage.','for_you','cat_cupboard_locks','Cupboard locks and safer storage','Cupboard Locks',2,'A toddler who can reach, copy and open more things may find cleaning products, medicines or sharp items quickly. Cupboard locks and safer storage help keep hazards out of reach while their curiosity and independence are racing ahead with you close by.','for_you'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_safer_home','Make exploring safer',8,true,'need_home_safety','A home for a quick explorer','Your toddler may suddenly reach higher, climb faster or copy more adult routines. A simple safety refresh helps the home match their new movement: stairs, cupboards, windows, small objects, bath time and food prep all need another look at this stage.','for_you','cat_furniture_window_checks','Furniture, stair and window checks','Furniture Window Checks',3,'Climbing often appears before judgement. Checking furniture, windows, stairs and tempting step-ups helps you spot risks created by new reach and speed. It is a practical refresh for the home your toddler is now exploring in quicker, braver ways with you close by.','for_you'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_safer_home','Make exploring safer',8,true,'need_home_safety','A home for a quick explorer','Your toddler may suddenly reach higher, climb faster or copy more adult routines. A simple safety refresh helps the home match their new movement: stairs, cupboards, windows, small objects, bath time and food prep all need another look at this stage.','for_you','cat_button_battery_check','Button battery and magnet sweep','Button Battery Check',4,'Button batteries, loose magnets and tiny parts can be easy to overlook until a toddler can reach higher, open drawers or mouth objects quickly. A quick sweep of toys, remotes and household items helps reduce serious hidden risks with you close by.','for_you'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_safer_home','Make exploring safer',8,true,'need_home_safety','A home for a quick explorer','Your toddler may suddenly reach higher, climb faster or copy more adult routines. A simple safety refresh helps the home match their new movement: stairs, cupboards, windows, small objects, bath time and food prep all need another look at this stage.','for_you','cat_bath_water_supervision','Bath and water supervision','Bath Water Supervision',5,'Bath play can be joyful, but water still needs close attention. At this age, your toddler may stand, reach, pour or try to climb, so bath-time toys and routines should stay simple, supervised and within arm’s reach with you close by.','for_you'),
  ('19-21m','19–21 months',19,21,true,'ent_cluster_19_21_safer_home','Make exploring safer',8,true,'need_home_safety','A home for a quick explorer','Your toddler may suddenly reach higher, climb faster or copy more adult routines. A simple safety refresh helps the home match their new movement: stairs, cupboards, windows, small objects, bath time and food prep all need another look at this stage.','for_you','cat_food_choking_safety_prep','Food and choking-safety prep','Food Choking Safety Prep',6,'As your toddler eats more independently, familiar foods can still need safe prep. Cutting grapes, avoiding hard round foods and supervising meals help reduce choking risks while they practise biting, chewing and feeding themselves in a calm, seated routine with you close by.','for_you'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_talk_stories','I’m telling you more',1,true,'need_language_sentences','Telling you more','Your toddler may be trying longer phrases, copying new words and asking for the same book again and again. Little chats, songs and picture stories help them hear how words fit together, while keeping talking part of ordinary meals, walks and sofa moments.','for_your_child','cat_picture_story_books','Books that start little chats','Picture Story Books',1,'Your toddler may point, name a picture or finish a line from a favourite book. Repeating familiar stories gives them words to join in with, while you can pause, ask simple questions and add one extra word to what they say.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_talk_stories','I’m telling you more',1,true,'need_language_sentences','Telling you more','Your toddler may be trying longer phrases, copying new words and asking for the same book again and again. Little chats, songs and picture stories help them hear how words fit together, while keeping talking part of ordinary meals, walks and sofa moments.','for_your_child','cat_conversation_games','Little conversation games','Conversation Games',2,'Walking to nursery, unpacking shopping or getting dressed can all become tiny talking games. Naming what you see, waiting for an answer and adding to your toddler’s words helps them practise longer phrases without making it feel like a lesson.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_talk_stories','I’m telling you more',1,true,'need_language_sentences','Telling you more','Your toddler may be trying longer phrases, copying new words and asking for the same book again and again. Little chats, songs and picture stories help them hear how words fit together, while keeping talking part of ordinary meals, walks and sofa moments.','for_your_child','cat_songs_action_games','Songs, rhymes and action games','Songs Action Games',3,'Your toddler may ask for the same rhyme again or copy the actions before the words arrive. Songs and action games give them a pattern to predict, join and repeat, supporting listening, memory and early turn-taking.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_talk_stories','I’m telling you more',1,true,'need_language_sentences','Telling you more','Your toddler may be trying longer phrases, copying new words and asking for the same book again and again. Little chats, songs and picture stories help them hear how words fit together, while keeping talking part of ordinary meals, walks and sofa moments.','for_your_child','cat_library_storytime','Library stories and rhyme sessions','Library Storytime',4,'A library trip can bring new pictures, voices and little routines into the week. Story or rhyme sessions give your toddler a chance to listen, join in and watch other children, while keeping book discovery low-cost and easy to refresh.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_pretend_helper_play','I’m copying the everyday',2,true,'need_pretend_imagination','Copying the everyday','Your toddler may be stirring an empty bowl, feeding teddy or making pretend cups of tea. Copying real life gives them a way to practise words, sequences, care and imagination, using the small household scenes they already know.','for_your_child','cat_play_kitchen_household_props','A play kitchen for everyday copying','Play Kitchen Household Props',1,'Your toddler may love copying the things they see at home, from stirring a bowl to washing a cup. A play kitchen or household props give that copying a place to go, helping them practise words, sequences and imagination.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_pretend_helper_play','I’m copying the everyday',2,true,'need_pretend_imagination','Copying the everyday','Your toddler may be stirring an empty bowl, feeding teddy or making pretend cups of tea. Copying real life gives them a way to practise words, sequences, care and imagination, using the small household scenes they already know.','for_your_child','cat_doll_soft_toy_care','Teddy and doll care play','Doll Soft Toy Care',2,'Feeding teddy, putting a doll to bed or finding a blanket for a soft toy lets your toddler act out care they recognise. It can bring out new words, early empathy and simple story steps while staying close to everyday life.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_pretend_helper_play','I’m copying the everyday',2,true,'need_pretend_imagination','Copying the everyday','Your toddler may be stirring an empty bowl, feeding teddy or making pretend cups of tea. Copying real life gives them a way to practise words, sequences, care and imagination, using the small household scenes they already know.','for_your_child','cat_toy_cups_spoons','Tea sets, cups and little plates','Toy Cups Spoons',3,'Tiny cups, plates and spoons can turn snacks, cafés and tea parties into pretend play. Your toddler can pour, serve, offer and ask for more, practising language and turn-taking through a scene they already understand.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_pretend_helper_play','I’m copying the everyday',2,true,'need_pretend_imagination','Copying the everyday','Your toddler may be stirring an empty bowl, feeding teddy or making pretend cups of tea. Copying real life gives them a way to practise words, sequences, care and imagination, using the small household scenes they already know.','for_your_child','cat_dress_up_role_play','Dress-up and getting-ready props','Dress Up Role Play',4,'Loose hats, bags, shoes and dressing-up pieces let your toddler copy leaving the house, brushing hair or getting teddy ready. These little scenes help them practise words, body awareness and routine steps without the pressure of the real morning.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_pretend_helper_play','I’m copying the everyday',2,true,'need_pretend_imagination','Copying the everyday','Your toddler may be stirring an empty bowl, feeding teddy or making pretend cups of tea. Copying real life gives them a way to practise words, sequences, care and imagination, using the small household scenes they already know.','for_your_child','cat_small_world_vehicles_figures','Little worlds with vehicles and figures','Small World Vehicles Figures',5,'Cars, animals or chunky figures can become shops, parks, buses or trips to see family. Moving the pieces around helps your toddler make little stories, solve tiny problems and use new words, especially when the parts are large and easy to handle.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_busy_hands_puzzles','My hands are getting busy',3,true,'need_fine_motor_problem_solving','Busy little hands','Your toddler may be turning puzzle pieces, sorting colours, stacking towers or making first marks. These satisfying hand challenges help them practise control, patience and problem-solving, especially when the pieces are chunky, washable and easy to try again.','for_your_child','cat_shape_sorters_puzzles','Chunky puzzles and shape sorters','Shape Sorters Puzzles',1,'Your toddler may turn a piece round and round before it suddenly fits. Chunky puzzles and sorters give them a clear hand challenge, helping them practise focus, matching, patience and the useful feeling of trying again.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_busy_hands_puzzles','My hands are getting busy',3,true,'need_fine_motor_problem_solving','Busy little hands','Your toddler may be turning puzzle pieces, sorting colours, stacking towers or making first marks. These satisfying hand challenges help them practise control, patience and problem-solving, especially when the pieces are chunky, washable and easy to try again.','for_your_child','cat_colour_sorting_matching','Colour matching and sorting games','Colour Sorting Matching',2,'Sorting red pieces together or matching socks by colour can feel like a small game. Moving objects into groups helps your toddler notice same and different, hear simple colour words and practise hand control at the same time.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_busy_hands_puzzles','My hands are getting busy',3,true,'need_fine_motor_problem_solving','Busy little hands','Your toddler may be turning puzzle pieces, sorting colours, stacking towers or making first marks. These satisfying hand challenges help them practise control, patience and problem-solving, especially when the pieces are chunky, washable and easy to try again.','for_your_child','cat_chunky_crayons','Chunky crayons and first marks','Chunky Crayons',3,'Dots, lines and early circles may not look like much yet, but they are real hand practice. Chunky crayons, chalk or washable markers let your toddler test grip, pressure and movement while seeing their ideas appear on paper.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_busy_hands_puzzles','My hands are getting busy',3,true,'need_fine_motor_problem_solving','Busy little hands','Your toddler may be turning puzzle pieces, sorting colours, stacking towers or making first marks. These satisfying hand challenges help them practise control, patience and problem-solving, especially when the pieces are chunky, washable and easy to try again.','for_your_child','cat_threading_beads','Chunky threading and lacing','Threading Beads',4,'Large beads or lacing boards ask your toddler to slow down, line things up and use two hands together. Keep pieces oversized and supervised, so the challenge feels satisfying rather than fiddly or unsafe.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_busy_hands_puzzles','My hands are getting busy',3,true,'need_fine_motor_problem_solving','Busy little hands','Your toddler may be turning puzzle pieces, sorting colours, stacking towers or making first marks. These satisfying hand challenges help them practise control, patience and problem-solving, especially when the pieces are chunky, washable and easy to try again.','for_your_child','cat_play_dough_tools','Play dough and squish tools','Play Dough Tools',5,'Rolling, poking, pressing and cutting dough gives your toddler plenty for their fingers and palms to do. Add a spoon, cutter or pretend cake moment and the play can become both hand practice and early imagination.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_busy_hands_puzzles','My hands are getting busy',3,true,'need_fine_motor_problem_solving','Busy little hands','Your toddler may be turning puzzle pieces, sorting colours, stacking towers or making first marks. These satisfying hand challenges help them practise control, patience and problem-solving, especially when the pieces are chunky, washable and easy to try again.','for_your_child','cat_stacking_pegboard','Pegboards, blocks and wobbly towers','Stacking Pegboard',6,'Stacking blocks, pegs or tiles lets your toddler test height, balance and what happens next. When the tower falls, they can change the plan, rebuild and talk about tall, more, again or crash.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_big_movement','I’m moving with more confidence',4,true,'need_gross_motor_outdoor','Moving with confidence','Your toddler may be running faster, climbing higher, kicking balls and testing what their body can do. Short, supervised movement games give that energy somewhere useful to go, while helping balance, coordination and confidence grow through play.','for_your_child','cat_soft_graspable_balls','Soft balls to kick and chase','Soft Graspable Balls',1,'A soft ball gives your toddler a reason to run, stop, kick, chase and try again. Rolling it back and forth can also become a first turn-taking game, with movement, words and laughter built in.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_big_movement','I’m moving with more confidence',4,true,'need_gross_motor_outdoor','Moving with confidence','Your toddler may be running faster, climbing higher, kicking balls and testing what their body can do. Short, supervised movement games give that energy somewhere useful to go, while helping balance, coordination and confidence grow through play.','for_your_child','cat_balance_bike_scooter','First balance bike or scooter goes','Balance Bike Scooter',2,'Some toddlers are ready for very short tries on a balance bike or scooter, especially with plenty of space and an adult close by. The value is steering, stopping and balance, not speed or distance.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_big_movement','I’m moving with more confidence',4,true,'need_gross_motor_outdoor','Moving with confidence','Your toddler may be running faster, climbing higher, kicking balls and testing what their body can do. Short, supervised movement games give that energy somewhere useful to go, while helping balance, coordination and confidence grow through play.','for_your_child','cat_climbing_frame_play','Playground climbs and running space','Climbing Frame Play',3,'Steps, slopes, slides and open space give your toddler a place to test climbing, running and stopping. Staying close helps you judge height, crowds and surfaces while they practise what their body can do.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_big_movement','I’m moving with more confidence',4,true,'need_gross_motor_outdoor','Moving with confidence','Your toddler may be running faster, climbing higher, kicking balls and testing what their body can do. Short, supervised movement games give that energy somewhere useful to go, while helping balance, coordination and confidence grow through play.','for_your_child','cat_follow_the_leader_games','Follow-the-leader movement games','Follow The Leader Games',4,'Tiptoeing down the hall, walking backwards or playing ready-set-go gives your toddler a reason to copy and control movement. It works in a hallway, garden or park, and you can make it as short as the day allows.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_big_movement','I’m moving with more confidence',4,true,'need_gross_motor_outdoor','Moving with confidence','Your toddler may be running faster, climbing higher, kicking balls and testing what their body can do. Short, supervised movement games give that energy somewhere useful to go, while helping balance, coordination and confidence grow through play.','for_your_child','cat_water_play_cups','Pouring cups for bath or garden','Water Play Cups',5,'Pouring water from one cup to another can hold a toddler’s attention for ages. It gives them practice with hand control, full and empty, more and all gone, as long as water play stays closely supervised.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_feelings_turn_taking','I’m learning to play with others',5,true,'need_social_emotional_turn_taking','Learning to play with others','Your toddler may be watching other children, copying what they do and finding waiting hard. Tiny turns, feeling words and short group moments help them practise being near people, sharing space and naming what is happening, with you close enough to help.','for_your_child','cat_feelings_faces_books','Books about faces and feelings','Feelings Faces Books',1,'Your toddler may recognise a sad face in a book before they can explain their own upset. Books about feelings give you easy words for happy, cross, worried or tired, away from the heat of the moment.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_feelings_turn_taking','I’m learning to play with others',5,true,'need_social_emotional_turn_taking','Learning to play with others','Your toddler may be watching other children, copying what they do and finding waiting hard. Tiny turns, feeling words and short group moments help them practise being near people, sharing space and naming what is happening, with you close enough to help.','for_your_child','cat_turn_taking_games','Tiny turn-taking games','Turn Taking Games',2,'Rolling a ball, taking turns with a car or knocking down skittles gives your toddler a simple rhythm: my turn, your turn. Short games make waiting feel more possible and keep social practice small enough to enjoy.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_feelings_turn_taking','I’m learning to play with others',5,true,'need_social_emotional_turn_taking','Learning to play with others','Your toddler may be watching other children, copying what they do and finding waiting hard. Tiny turns, feeling words and short group moments help them practise being near people, sharing space and naming what is happening, with you close enough to help.','for_your_child','cat_visual_choice_cards','Choice cards and simple options','Visual Choice Cards',3,'Two clear choices can help your toddler feel involved without opening up the whole day. Picture cards or simple prompts can support clothes, snacks, routines or play, especially when words are still catching up with feelings.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_feelings_turn_taking','I’m learning to play with others',5,true,'need_social_emotional_turn_taking','Learning to play with others','Your toddler may be watching other children, copying what they do and finding waiting hard. Tiny turns, feeling words and short group moments help them practise being near people, sharing space and naming what is happening, with you close enough to help.','for_your_child','cat_calm_corner_tools','Quiet basket for big feelings','Calm Corner Tools',4,'A small basket with books, soft toys or feeling cards can give your toddler a familiar place to pause with you nearby. It is not a punishment space; it is a way to reconnect, name feelings and try again.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_feelings_turn_taking','I’m learning to play with others',5,true,'need_social_emotional_turn_taking','Learning to play with others','Your toddler may be watching other children, copying what they do and finding waiting hard. Tiny turns, feeling words and short group moments help them practise being near people, sharing space and naming what is happening, with you close enough to help.','for_your_child','cat_playdate_library_groups','Playgroups, parks and little meetups','Playdate Library Groups',5,'Short playgroups, park trips or library sessions give toddlers a chance to play near others, copy, wait and join in. You can stay close, model words and keep expectations realistic while they learn how shared play works.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_independence_practice','I want to do it myself',6,true,'need_independence_self_care','Doing it myself','You may be hearing more “me do it” moments now. A steady step, easy clothes, picture routines and toddler-sized mealtime tools can help your child try small jobs for themselves, while you stay close enough to guide, steady and reset.','for_your_child','cat_step_stool','A steady step for helping','Step Stool',1,'A steady low step can help your toddler reach the sink, wash hands or join a small job. It works best for short helper moments, with you close by and the step on a stable surface.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_independence_practice','I want to do it myself',6,true,'need_independence_self_care','Doing it myself','You may be hearing more “me do it” moments now. A steady step, easy clothes, picture routines and toddler-sized mealtime tools can help your child try small jobs for themselves, while you stay close enough to guide, steady and reset.','for_your_child','cat_dressing_practice','Easy clothes and dressing games','Dressing Practice',2,'Loose trousers, open jackets and playful dressing games let your toddler practise pulling, pushing and choosing. These tiny steps build confidence and body awareness, even when the real morning still needs adult hands.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_independence_practice','I want to do it myself',6,true,'need_independence_self_care','Doing it myself','You may be hearing more “me do it” moments now. A steady step, easy clothes, picture routines and toddler-sized mealtime tools can help your child try small jobs for themselves, while you stay close enough to guide, steady and reset.','for_your_child','cat_routine_cards','Picture routines and tidy-up cues','Routine Cards',3,'Simple pictures can show what comes next: shoes, snack, tidy up, bath, book. Seeing the steps can reduce negotiation and give your toddler a small structure for doing more without asking them to remember everything.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_independence_practice','I want to do it myself',6,true,'need_independence_self_care','Doing it myself','You may be hearing more “me do it” moments now. A steady step, easy clothes, picture routines and toddler-sized mealtime tools can help your child try small jobs for themselves, while you stay close enough to guide, steady and reset.','for_your_child','cat_first_spoons_bowls','Toddler spoons, bowls and small servings','First Spoons Bowls',4,'A toddler spoon, stable bowl or small serving can let your child practise feeding themselves without making every meal a test. Expect mess; the useful bit is hand control, choice and the pride of having a go.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_independence_practice','I want to do it myself',6,true,'need_independence_self_care','Doing it myself','You may be hearing more “me do it” moments now. A steady step, easy clothes, picture routines and toddler-sized mealtime tools can help your child try small jobs for themselves, while you stay close enough to guide, steady and reset.','for_your_child','cat_handwashing_routine','Handwashing songs and sink routine','Handwashing Routine',5,'A little song, steady step and repeated sink routine can help handwashing become familiar after potty tries, messy play or meals. The goal is not getting every step right; it is building the pattern together.','for_your_child'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_potty_toilet_practice','I’m noticing potty signs',7,true,'need_potty_toilet_awareness','Noticing potty signs','Some toddlers start showing interest in wee, poo, potties or bathroom routines around now. Others need more time. Potty seats, books, easy-off clothes and handwashing cues can make the pieces feel familiar before you ask your child to put them all together.','for_both','cat_potty','A potty to practise sitting','Potty',1,'A potty can help your toddler practise sitting, noticing body signals and joining bathroom routines. Keep it low-pressure and familiar, especially if they show interest or you are starting to prepare for nappy-free moments.','for_both'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_potty_toilet_practice','I’m noticing potty signs',7,true,'need_potty_toilet_awareness','Noticing potty signs','Some toddlers start showing interest in wee, poo, potties or bathroom routines around now. Others need more time. Potty seats, books, easy-off clothes and handwashing cues can make the pieces feel familiar before you ask your child to put them all together.','for_both','cat_toilet_training_seat','A child seat for the toilet','Toilet Training Seat',2,'Some toddlers prefer the toilet with a child seat rather than a separate potty. A stable seat can make the big toilet feel less daunting and can sit alongside potty practice, depending on what your child accepts.','for_both'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_potty_toilet_practice','I’m noticing potty signs',7,true,'need_potty_toilet_awareness','Noticing potty signs','Some toddlers start showing interest in wee, poo, potties or bathroom routines around now. Others need more time. Potty seats, books, easy-off clothes and handwashing cues can make the pieces feel familiar before you ask your child to put them all together.','for_both','cat_training_pants','Training pants and easy-off clothes','Training Pants',3,'Training pants and easy-off clothing can make early potty practice more manageable for everyone. They support quick trips, small accidents and little independence moments without making success feel all-or-nothing.','for_both'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_potty_toilet_practice','I’m noticing potty signs',7,true,'need_potty_toilet_awareness','Noticing potty signs','Some toddlers start showing interest in wee, poo, potties or bathroom routines around now. Others need more time. Potty seats, books, easy-off clothes and handwashing cues can make the pieces feel familiar before you ask your child to put them all together.','for_both','cat_potty_training_books','Potty books and bathroom stories','Potty Training Books',4,'A simple potty book can make wee, poo, wiping and handwashing easier to discuss before the moment arrives. It gives your toddler shared words for a new routine and keeps the topic light.','for_both'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_potty_toilet_practice','I’m noticing potty signs',7,true,'need_potty_toilet_awareness','Noticing potty signs','Some toddlers start showing interest in wee, poo, potties or bathroom routines around now. Others need more time. Potty seats, books, easy-off clothes and handwashing cues can make the pieces feel familiar before you ask your child to put them all together.','for_both','cat_sticker_chart','A gentle sticker chart','Sticker Chart',5,'Some toddlers like seeing what they are practising. A small sticker chart can make tries, sits or handwashing steps more visible, as long as it celebrates effort and routines rather than making accidents feel like failure.','for_both'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_home_rhythm_safety','Keep curious days safer',8,true,'need_parent_routines_safety','Keeping busy days safer','Your toddler may be taller, quicker and more determined than the home setup expects. Familiar bedtime steps, easier mealtimes and a fresh check for batteries, small objects, windows and furniture can help the day feel more manageable while the bigger risks stay out of reach.','for_you','cat_bedtime_board_books','Bedtime books with familiar steps','Bedtime Board Books',1,'A short, familiar book can become a cue that bedtime is coming. Repeating the same few steps each night helps your toddler know what to expect, especially when delay tactics and independence are getting stronger.','for_you'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_home_rhythm_safety','Keep curious days safer',8,true,'need_parent_routines_safety','Keeping busy days safer','Your toddler may be taller, quicker and more determined than the home setup expects. Familiar bedtime steps, easier mealtimes and a fresh check for batteries, small objects, windows and furniture can help the day feel more manageable while the bigger risks stay out of reach.','for_you','cat_comfort_toy','A safe comfort toy','Comfort Toy',2,'A favourite soft toy or blanket can help some toddlers settle, especially if they wake at night. Choose something simple and familiar, then check it often for loose parts, worn seams or anything that could become unsafe.','for_you'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_home_rhythm_safety','Keep curious days safer',8,true,'need_parent_routines_safety','Keeping busy days safer','Your toddler may be taller, quicker and more determined than the home setup expects. Familiar bedtime steps, easier mealtimes and a fresh check for batteries, small objects, windows and furniture can help the day feel more manageable while the bigger risks stay out of reach.','for_you','cat_family_mealtime_setup','Small portions and family meals','Family Mealtime Setup',3,'Small portions, repeated offers and eating together can make mealtimes feel less loaded when your toddler refuses foods. The aim is steady exposure and connection, not winning every meal or turning food into a battle.','for_you'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_home_rhythm_safety','Keep curious days safer',8,true,'need_parent_routines_safety','Keeping busy days safer','Your toddler may be taller, quicker and more determined than the home setup expects. Familiar bedtime steps, easier mealtimes and a fresh check for batteries, small objects, windows and furniture can help the day feel more manageable while the bigger risks stay out of reach.','for_you','cat_button_battery_check','A button battery sweep','Button Battery Check',4,'A faster, taller toddler can reach remotes, key fobs, cards, toys and drawers you had not noticed before. A quick button battery sweep is a small job with a serious safety purpose.','for_you'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_home_rhythm_safety','Keep curious days safer',8,true,'need_parent_routines_safety','Keeping busy days safer','Your toddler may be taller, quicker and more determined than the home setup expects. Familiar bedtime steps, easier mealtimes and a fresh check for batteries, small objects, windows and furniture can help the day feel more manageable while the bigger risks stay out of reach.','for_you','cat_furniture_window_checks','Furniture, stair and window checks','Furniture Window Checks',5,'When toddlers climb higher and move faster, furniture, stairs and windows deserve a fresh look. Anchoring furniture, moving climbable items away from windows and checking safer storage can reduce the bigger risks.','for_you'),
  ('25-27m','25–27 months',25,27,true,'ent_cluster_home_rhythm_safety','Keep curious days safer',8,true,'need_parent_routines_safety','Keeping busy days safer','Your toddler may be taller, quicker and more determined than the home setup expects. Familiar bedtime steps, easier mealtimes and a fresh check for batteries, small objects, windows and furniture can help the day feel more manageable while the bigger risks stay out of reach.','for_you','cat_choking_hazard_sweep','Small-object and choking sweep','Choking Hazard Sweep',6,'Toddlers still explore quickly, especially when older-child toys, craft bits or household items are nearby. A quick sweep for small parts, magnets, batteries and unsafe food shapes helps make play and mealtimes safer.','for_you'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_talk_stories_questions','I’m telling little stories',1,true,'ent_need_language_stories','Telling little stories','Your toddler may be naming pictures, asking little questions or turning everyday moments into mini stories. Books, songs and chat can make language feel warm and useful, while giving them space to try new words without turning home into a lesson.','for_your_child','cat_picture_story_books','Picture books with little stories','Picture Story Books',1,'Looking at pictures, naming what you see and asking little questions can make books feel more interactive now. Story books give your toddler a gentle way to practise new words, remember familiar scenes and connect language with people, places and feelings.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_talk_stories_questions','I’m telling little stories',1,true,'ent_need_language_stories','Telling little stories','Your toddler may be naming pictures, asking little questions or turning everyday moments into mini stories. Books, songs and chat can make language feel warm and useful, while giving them space to try new words without turning home into a lesson.','for_your_child','cat_conversation_prompt_cards','Little question prompts','Conversation Prompt Cards',2,'Simple picture or question prompts can help when tired-parent brain is real. Used gently, they give your toddler more chances to name, choose, describe and answer, without making language practice feel formal, test-like or separate from normal family chat. A few prompts are enough.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_talk_stories_questions','I’m telling little stories',1,true,'ent_need_language_stories','Telling little stories','Your toddler may be naming pictures, asking little questions or turning everyday moments into mini stories. Books, songs and chat can make language feel warm and useful, while giving them space to try new words without turning home into a lesson.','for_your_child','cat_songs_action_games','Songs with actions and silly sounds','Songs Action Games',3,'Songs with actions, silly sounds and repeated phrases give your toddler another way to join in with language. They can practise listening, copying, choosing words and moving their body, while the repetition helps new words stick and gives tired adults an easy place to start.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_talk_stories_questions','I’m telling little stories',1,true,'ent_need_language_stories','Telling little stories','Your toddler may be naming pictures, asking little questions or turning everyday moments into mini stories. Books, songs and chat can make language feel warm and useful, while giving them space to try new words without turning home into a lesson.','for_your_child','cat_feelings_faces_books','Feeling faces and story books','Feelings Faces Books',4,'Books or cards about faces and feelings can help toddlers name what is happening inside and around them. They also create gentle openings to talk about sharing, waiting, frustration and care, especially as peer play becomes more common and feelings show up loudly.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_pretend_social_worlds','I’m making pretend worlds',2,true,'ent_need_pretend_peer_play','Making pretend worlds','Pretend play may be getting richer now: teddy needs tea, a box becomes a shop, or another child joins the story. These little scenes help toddlers practise words, feelings, turn-taking and confidence in a way that still feels like play.','for_your_child','cat_doll_soft_toy_care','Teddy and doll care play','Doll Soft Toy Care',1,'Feeding teddy, dressing a doll or putting a soft toy to bed lets your toddler practise care, language and sequencing. These small pretend scenes can also help them explore feelings and everyday routines safely, without needing complicated toys or a big setup.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_pretend_social_worlds','I’m making pretend worlds',2,true,'ent_need_pretend_peer_play','Making pretend worlds','Pretend play may be getting richer now: teddy needs tea, a box becomes a shop, or another child joins the story. These little scenes help toddlers practise words, feelings, turn-taking and confidence in a way that still feels like play.','for_your_child','cat_play_kitchen_household_props','Play kitchen and home props','Play Kitchen Household Props',2,'Pretend cooking, shopping or making tea lets your toddler copy familiar routines and create little scenes. Safe household props and play food can support imagination, words, turn-taking and problem-solving, especially when an adult follows their lead and adds simple language.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_pretend_social_worlds','I’m making pretend worlds',2,true,'ent_need_pretend_peer_play','Making pretend worlds','Pretend play may be getting richer now: teddy needs tea, a box becomes a shop, or another child joins the story. These little scenes help toddlers practise words, feelings, turn-taking and confidence in a way that still feels like play.','for_your_child','cat_small_world_figures','Small-world people and vehicles','Small World Figures',3,'Little people, vehicles, animals or buildings can help toddlers act out the world they see every day. At this age, small-world play can turn into early stories, problem-solving and social scripts, especially when adults add words without taking over the plot.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_pretend_social_worlds','I’m making pretend worlds',2,true,'ent_need_pretend_peer_play','Making pretend worlds','Pretend play may be getting richer now: teddy needs tea, a box becomes a shop, or another child joins the story. These little scenes help toddlers practise words, feelings, turn-taking and confidence in a way that still feels like play.','for_your_child','cat_puppets','Puppets and silly voices','Puppets',4,'A puppet can make conversation feel less direct and more fun. Your toddler may answer the puppet, feed it, hide it or give it a voice, practising words, turn-taking and pretend play without feeling put on the spot. Keep it small and follow their lead.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_pretend_social_worlds','I’m making pretend worlds',2,true,'ent_need_pretend_peer_play','Making pretend worlds','Pretend play may be getting richer now: teddy needs tea, a box becomes a shop, or another child joins the story. These little scenes help toddlers practise words, feelings, turn-taking and confidence in a way that still feels like play.','for_your_child','cat_peer_play_books','Stories about sharing and friends','Peer Play Books',5,'Stories about sharing, waiting, feelings and friends can give your toddler words for moments that still feel hard. Reading them together can make peer play easier to talk about, especially before nursery, playdates or busy group settings where big feelings often arrive.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_puzzles_patterns_problem_solving','I’m figuring things out',3,true,'ent_need_problem_solving_patterns','Figuring things out','Matching colours, turning pieces, remembering where things are and pouring water can all feel satisfying at this stage. These playful challenges help your toddler practise focus, planning and early problem-solving, especially when the answer is something they can see or feel.','for_your_child','cat_shape_peg_puzzles','Chunky puzzles they can turn','Shape Peg Puzzles',1,'Chunky puzzles let your toddler turn pieces around, try again and see when something fits. That simple loop supports focus, hand control and problem-solving, while giving them the satisfying feeling of finishing something themselves with a little help nearby. A little help nearby is enough.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_puzzles_patterns_problem_solving','I’m figuring things out',3,true,'ent_need_problem_solving_patterns','Figuring things out','Matching colours, turning pieces, remembering where things are and pouring water can all feel satisfying at this stage. These playful challenges help your toddler practise focus, planning and early problem-solving, especially when the answer is something they can see or feel.','for_your_child','cat_twist_pivot_puzzles','Twist, turn and latch puzzles','Twist Pivot Puzzles',2,'Twisting, sliding, opening and turning parts gives your toddler a hands-on problem to work through. These puzzles can build patience, hand strength and planning, especially when the challenge is clear enough to try again without frustration taking over. A small success can keep them going.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_puzzles_patterns_problem_solving','I’m figuring things out',3,true,'ent_need_problem_solving_patterns','Figuring things out','Matching colours, turning pieces, remembering where things are and pouring water can all feel satisfying at this stage. These playful challenges help your toddler practise focus, planning and early problem-solving, especially when the answer is something they can see or feel.','for_your_child','cat_colour_matching_games','Colour sorting and matching games','Colour Matching Games',3,'Matching socks, blocks, cards or counters by colour can make early colour words feel useful. Your toddler gets to compare, choose and sort in a way they can see, while practising attention, simple decisions and everyday naming. Everyday objects work well for this.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_puzzles_patterns_problem_solving','I’m figuring things out',3,true,'ent_need_problem_solving_patterns','Figuring things out','Matching colours, turning pieces, remembering where things are and pouring water can all feel satisfying at this stage. These playful challenges help your toddler practise focus, planning and early problem-solving, especially when the answer is something they can see or feel.','for_your_child','cat_memory_matching_games','Simple memory pairs','Memory Matching Games',4,'A few picture pairs can help your toddler practise looking carefully, remembering and waiting for a turn. Keep the set small at first, so the game feels playful and achievable rather than like a test. Two or three pairs are plenty.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_puzzles_patterns_problem_solving','I’m figuring things out',3,true,'ent_need_problem_solving_patterns','Figuring things out','Matching colours, turning pieces, remembering where things are and pouring water can all feel satisfying at this stage. These playful challenges help your toddler practise focus, planning and early problem-solving, especially when the answer is something they can see or feel.','for_your_child','cat_pouring_volume_play','Pouring and water play','Pouring Volume Play',5,'Pouring water between cups, jugs or bath containers lets your toddler explore movement, volume and control. It also gives them a safe way to repeat an experiment again and again, which is exactly how many toddlers learn. The repetition is part of the learning.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_busy_hands_making_marks','My hands are getting busy',4,true,'ent_need_fine_motor_mark_making','Busy little hands','Your toddler may be more interested in making marks, peeling stickers, squashing dough or trying careful finger jobs. These hands-on moments help build control for drawing, feeding, dressing and play, while letting them make something that feels proudly theirs, even when it looks wonderfully messy.','for_your_child','cat_chunky_crayons','Chunky crayons and big scribbles','Chunky Crayons',1,'Chunky crayons give your toddler a comfortable way to make big lines, dots and circles. Scribbling is not just mess: it helps them connect hand movement with marks on a page, building control for later drawing and writing. Big paper makes it easier to enjoy.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_busy_hands_making_marks','My hands are getting busy',4,true,'ent_need_fine_motor_mark_making','Busy little hands','Your toddler may be more interested in making marks, peeling stickers, squashing dough or trying careful finger jobs. These hands-on moments help build control for drawing, feeding, dressing and play, while letting them make something that feels proudly theirs, even when it looks wonderfully messy.','for_your_child','cat_play_dough_soft_clay','Soft dough for squashing and shaping','Play Dough Soft Clay',2,'Squashing, rolling and pinching soft dough gives busy hands a satisfying job. It can support finger strength, imagination and calm focus, especially when the play stays simple: make a sausage, press a shape, squash it flat and start again. Keep pieces large and supervise closely.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_busy_hands_making_marks','My hands are getting busy',4,true,'ent_need_fine_motor_mark_making','Busy little hands','Your toddler may be more interested in making marks, peeling stickers, squashing dough or trying careful finger jobs. These hands-on moments help build control for drawing, feeding, dressing and play, while letting them make something that feels proudly theirs, even when it looks wonderfully messy.','for_your_child','cat_threading_beads','Chunky lacing and threading','Threading Beads',3,'Large beads, lacing cards or threading shapes can give your toddler a careful hand challenge. They practise aiming, holding steady and using both hands together, which supports dressing, feeding and early making skills without needing tiny, fiddly pieces. Choose large pieces and supervise closely.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_busy_hands_making_marks','My hands are getting busy',4,true,'ent_need_fine_motor_mark_making','Busy little hands','Your toddler may be more interested in making marks, peeling stickers, squashing dough or trying careful finger jobs. These hands-on moments help build control for drawing, feeding, dressing and play, while letting them make something that feels proudly theirs, even when it looks wonderfully messy.','for_your_child','cat_stickers_collage','Stickers and simple collage','Stickers Collage',4,'Peeling stickers, choosing where they go and pressing them down gives your toddler a small, satisfying finger job. Collage play can also help them make choices, talk about colours and create something without needing neat results. Neat results are not the point.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_busy_hands_making_marks','My hands are getting busy',4,true,'ent_need_fine_motor_mark_making','Busy little hands','Your toddler may be more interested in making marks, peeling stickers, squashing dough or trying careful finger jobs. These hands-on moments help build control for drawing, feeding, dressing and play, while letting them make something that feels proudly theirs, even when it looks wonderfully messy.','for_your_child','cat_tongs_scoops','Scoops, tongs and little transfers','Tongs Scoops',5,'Moving pom-poms, pasta or bath toys with scoops and tongs can turn hand practice into a game. These little transfer jobs help build grip, coordination and concentration, while still feeling like play rather than practice. Keep pieces large and supervise closely.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_jumping_balance_big_moves','I’m trying bigger moves',5,true,'ent_need_gross_motor_balance','Bigger moves','At this stage, many toddlers want bigger physical challenges: jumping, kicking, climbing, balancing or pedalling. Simple movement games give them a reason to practise coordination, strength and confidence, while helping all that energy land somewhere a little safer and more predictable.','for_your_child','cat_jump_hoops_beanbags','Hoops, beanbags and jump games','Jump Hoops Beanbags',1,'Jumping into a hoop, landing on a cushion or tossing a beanbag gives your toddler a clear movement goal. These games can support balance, coordination and body confidence, especially when the challenge is small, safe and easy to repeat. Start small and stay close as they try.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_jumping_balance_big_moves','I’m trying bigger moves',5,true,'ent_need_gross_motor_balance','Bigger moves','At this stage, many toddlers want bigger physical challenges: jumping, kicking, climbing, balancing or pedalling. Simple movement games give them a reason to practise coordination, strength and confidence, while helping all that energy land somewhere a little safer and more predictable.','for_your_child','cat_large_balls','Big balls for kicking and catching','Large Balls',2,'Kicking, rolling and catching a larger ball gives your toddler a simple way to practise timing, balance and turn-taking. Keep the distance short and the ball easy to see, so the game feels rewarding and both of you know when it is your turn.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_jumping_balance_big_moves','I’m trying bigger moves',5,true,'ent_need_gross_motor_balance','Bigger moves','At this stage, many toddlers want bigger physical challenges: jumping, kicking, climbing, balancing or pedalling. Simple movement games give them a reason to practise coordination, strength and confidence, while helping all that energy land somewhere a little safer and more predictable.','for_your_child','cat_balance_stepping_stones','Balance paths and stepping stones','Balance Stepping Stones',3,'A simple balance path lets your toddler step, wobble, pause and try again. Cushions, mats or stepping stones can make balance practice feel like an adventure, while keeping the challenge close to the ground and easy to reset. Start low and stay close as they try.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_jumping_balance_big_moves','I’m trying bigger moves',5,true,'ent_need_gross_motor_balance','Bigger moves','At this stage, many toddlers want bigger physical challenges: jumping, kicking, climbing, balancing or pedalling. Simple movement games give them a reason to practise coordination, strength and confidence, while helping all that energy land somewhere a little safer and more predictable.','for_your_child','cat_park_climbing_play','Park climbs and obstacle games','Park Climbing Play',4,'Climbing a low frame, stepping over logs or crawling through a tunnel gives bigger movement somewhere to go. With close supervision, obstacle play helps your toddler test strength, planning and courage without making the whole house the climbing frame. Stay close and choose low challenges first.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_jumping_balance_big_moves','I’m trying bigger moves',5,true,'ent_need_gross_motor_balance','Bigger moves','At this stage, many toddlers want bigger physical challenges: jumping, kicking, climbing, balancing or pedalling. Simple movement games give them a reason to practise coordination, strength and confidence, while helping all that energy land somewhere a little safer and more predictable.','for_your_child','cat_tricycle_scooter','Trikes and beginner scooters','Tricycle Scooter',5,'Some toddlers may be ready to try a trike, ride-on or beginner scooter with close adult help. These can support balance, steering and confidence, especially when used slowly in safe spaces with a well-fitting helmet where needed. Start slowly and keep routes simple.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_little_helper_independence','I want to do it myself',6,true,'ent_need_independence_routines','Doing more myself','Your toddler may want to help, choose, carry, dress, clean up or reach things for themselves. Small, safe routines can turn that push for independence into confidence and cooperation, while keeping grown-ups close enough to guide the bits that still need help.','for_your_child','cat_learning_tower_step_stool','A safe step up for helping','Learning Tower Step Stool',1,'A stable learning tower or step stool can help your toddler join washing, cooking or brushing routines at the right height. It supports independence and everyday language, as long as an adult stays close and the setup is stable. Stability matters more than independence points.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_little_helper_independence','I want to do it myself',6,true,'ent_need_independence_routines','Doing more myself','Your toddler may want to help, choose, carry, dress, clean up or reach things for themselves. Small, safe routines can turn that push for independence into confidence and cooperation, while keeping grown-ups close enough to guide the bits that still need help.','for_your_child','cat_visual_routine_cards','Picture routines and simple timers','Visual Routine Cards',2,'A picture routine or simple timer can make transitions feel less surprising. Your toddler can see what is happening next, practise choosing or waiting, and feel more involved in everyday jobs like getting dressed or leaving the house. A few steps are usually enough.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_little_helper_independence','I want to do it myself',6,true,'ent_need_independence_routines','Doing more myself','Your toddler may want to help, choose, carry, dress, clean up or reach things for themselves. Small, safe routines can turn that push for independence into confidence and cooperation, while keeping grown-ups close enough to guide the bits that still need help.','for_your_child','cat_dressing_practice_clothes','Easy dressing practice','Dressing Practice Clothes',3,'Loose socks, big zips, simple fastenings or dressing-up clothes give your toddler a chance to practise without the full pressure of getting ready. These small wins can build hand control, patience and confidence before the morning rush. Practise away from the morning rush.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_little_helper_independence','I want to do it myself',6,true,'ent_need_independence_routines','Doing more myself','Your toddler may want to help, choose, carry, dress, clean up or reach things for themselves. Small, safe routines can turn that push for independence into confidence and cooperation, while keeping grown-ups close enough to guide the bits that still need help.','for_your_child','cat_safe_food_prep_tools','Toddler-safe food prep tools','Safe Food Prep Tools',4,'Child-safe spreading, stirring or washing jobs can help your toddler feel useful in the kitchen. Simple food prep supports independence, hand control and language, especially when the task is short, supervised and genuinely helpful rather than a pretend chore. Supervision stays part of the setup.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_little_helper_independence','I want to do it myself',6,true,'ent_need_independence_routines','Doing more myself','Your toddler may want to help, choose, carry, dress, clean up or reach things for themselves. Small, safe routines can turn that push for independence into confidence and cooperation, while keeping grown-ups close enough to guide the bits that still need help.','for_your_child','cat_cleanup_basket','Little tidy-up jobs','Cleanup Basket',5,'A small basket, clear home for toys or one-song tidy-up can make cleaning up feel more manageable. Your toddler gets to practise sorting, carrying and finishing a job, while the routine stays simple enough to repeat. One small job is enough to start.','for_your_child'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_potty_teeth_body_routines','Potty, teeth and little routines',7,true,'ent_need_potty_teeth_hygiene','Potty, teeth and little routines','Toileting, toothbrushing and handwashing can all become bigger family routines around this stage. The aim is not pressure or perfection. Familiar tools, clear words and repeated little steps can help your toddler understand what happens next and feel more involved.','for_both','cat_potty_chair','A potty that feels familiar','Potty Chair',1,'A potty can help toileting become part of the room rather than a sudden event. Keeping the tone calm, naming what it is for and letting your toddler explore it without pressure can make early readiness signs easier to notice.','for_both'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_potty_teeth_body_routines','Potty, teeth and little routines',7,true,'ent_need_potty_teeth_hygiene','Potty, teeth and little routines','Toileting, toothbrushing and handwashing can all become bigger family routines around this stage. The aim is not pressure or perfection. Familiar tools, clear words and repeated little steps can help your toddler understand what happens next and feel more involved.','for_both','cat_toilet_training_seat_step','Toilet seat and steady step','Toilet Training Seat Step',2,'A toilet training seat and sturdy step can help some toddlers feel more secure when they are ready to try the toilet. Feet support, calm words and short attempts matter more than rushing the result. Short, calm tries are enough.','for_both'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_potty_teeth_body_routines','Potty, teeth and little routines',7,true,'ent_need_potty_teeth_hygiene','Potty, teeth and little routines','Toileting, toothbrushing and handwashing can all become bigger family routines around this stage. The aim is not pressure or perfection. Familiar tools, clear words and repeated little steps can help your toddler understand what happens next and feel more involved.','for_both','cat_handwashing_step_stool','Handwashing step and soap routine','Handwashing Step Stool',3,'A safe step, easy soap and simple words can help handwashing become part of the routine after toileting, meals or messy play. Your toddler can practise reaching, rubbing, rinsing and drying with close grown-up help. Repeat the same words each time.','for_both'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_potty_teeth_body_routines','Potty, teeth and little routines',7,true,'ent_need_potty_teeth_hygiene','Potty, teeth and little routines','Toileting, toothbrushing and handwashing can all become bigger family routines around this stage. The aim is not pressure or perfection. Familiar tools, clear words and repeated little steps can help your toddler understand what happens next and feel more involved.','for_both','cat_toothbrush_toothpaste','Toddler toothbrush and toothpaste','Toothbrush Toothpaste',4,'A toddler toothbrush and age-appropriate fluoride toothpaste keep toothbrushing practical at this stage. Letting your child hold a brush can build familiarity, while an adult still does the careful brushing and keeps toothpaste amounts safe. Supervision stays part of every brush.','for_both'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_potty_teeth_body_routines','Potty, teeth and little routines',7,true,'ent_need_potty_teeth_hygiene','Potty, teeth and little routines','Toileting, toothbrushing and handwashing can all become bigger family routines around this stage. The aim is not pressure or perfection. Familiar tools, clear words and repeated little steps can help your toddler understand what happens next and feel more involved.','for_both','cat_potty_story_books','Potty stories and pictures','Potty Story Books',5,'Potty stories can make toileting language feel familiar before or during training. They help toddlers see what might happen next, ask questions and talk about bodies, pants and accidents without the whole routine becoming a big event. Keep the tone calm and ordinary.','for_both'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_safer_spaces_bigger_curiosity','A safer home for bigger curiosity',8,true,'ent_need_safe_home_setup','Safer home, bigger curiosity','As your toddler climbs, twists, carries, opens and experiments more, your home may need a fresh safety pass. Small checks around toy parts, batteries, magnets, cords, storage and routines can reduce avoidable risks while keeping everyday play open and calm.','for_you','cat_small_object_sweep','Tiny-object safety sweep','Small Object Sweep',1,'As toddlers open, carry, hide and test more things, small objects can appear in new places. A quick sweep for loose toy parts, coins, beads or older-child pieces helps keep play safer without needing to remove every interesting thing. Keep checks calm and routine, not scary.','for_you'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_safer_spaces_bigger_curiosity','A safer home for bigger curiosity',8,true,'ent_need_safe_home_setup','Safer home, bigger curiosity','As your toddler climbs, twists, carries, opens and experiments more, your home may need a fresh safety pass. Small checks around toy parts, batteries, magnets, cords, storage and routines can reduce avoidable risks while keeping everyday play open and calm.','for_you','cat_button_battery_check','Battery and magnet checks','Button Battery Check',2,'Button batteries and strong magnets can be serious hazards if swallowed. Checking toys, remotes, cards, lights and novelty items helps you spot loose compartments or risky pieces before they end up in curious hands or mixed into everyday play. Keep checks calm and routine, not scary.','for_you'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_safer_spaces_bigger_curiosity','A safer home for bigger curiosity',8,true,'ent_need_safe_home_setup','Safer home, bigger curiosity','As your toddler climbs, twists, carries, opens and experiments more, your home may need a fresh safety pass. Small checks around toy parts, batteries, magnets, cords, storage and routines can reduce avoidable risks while keeping everyday play open and calm.','for_you','cat_toy_rotation','Toy rotation and reset basket','Toy Rotation',3,'Putting a few toys away and bringing others back later can make familiar things feel new again. A simple reset basket also makes tidying easier, helps choices feel less overwhelming and can reduce the urge to buy more. A small swap can be enough.','for_you'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_safer_spaces_bigger_curiosity','A safer home for bigger curiosity',8,true,'ent_need_safe_home_setup','Safer home, bigger curiosity','As your toddler climbs, twists, carries, opens and experiments more, your home may need a fresh safety pass. Small checks around toy parts, batteries, magnets, cords, storage and routines can reduce avoidable risks while keeping everyday play open and calm.','for_you','cat_battery_free_toys','Battery-free play choices','Battery Free Toys',4,'Blocks, dolls, vehicles, puzzles and pretend props can be easier to inspect and use in many ways. Choosing some battery-free toys keeps play open-ended, reduces hidden hazard checks and often makes second-hand reuse simpler. A few open-ended choices are enough.','for_you'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_safer_spaces_bigger_curiosity','A safer home for bigger curiosity',8,true,'ent_need_safe_home_setup','Safer home, bigger curiosity','As your toddler climbs, twists, carries, opens and experiments more, your home may need a fresh safety pass. Small checks around toy parts, batteries, magnets, cords, storage and routines can reduce avoidable risks while keeping everyday play open and calm.','for_you','cat_nursery_spare_bag_labels','Nursery spares and labels','Nursery Spare Bag Labels',5,'Spare clothes, labelled items and a simple bag system can make nursery or childcare days easier. It supports toileting, messy play and dressing independence while helping grown-ups find the right things quickly when routines get busy. Keep the system simple enough to repeat.','for_you'),
  ('31-33m','31–33 months',31,33,true,'ent_cluster_safer_spaces_bigger_curiosity','A safer home for bigger curiosity',8,true,'ent_need_safe_home_setup','Safer home, bigger curiosity','As your toddler climbs, twists, carries, opens and experiments more, your home may need a fresh safety pass. Small checks around toy parts, batteries, magnets, cords, storage and routines can reduce avoidable risks while keeping everyday play open and calm.','for_you','cat_storage_baskets_shelves','Low baskets and easy shelves','Storage Baskets Shelves',6,'Low baskets or open shelves let your toddler see, choose and put things back with help. This supports independence and tidying, while keeping small parts, fragile items or safety-sensitive things out of reach and easier for adults to check. Simple labels can help grown-ups too.','for_you');

CREATE TEMP TABLE tmp_discover_stage1_wrappers AS
SELECT
  s.stage1_wrapper_ux_slug,
  s.stage1_wrapper_ux_label,
  NULLIF(TRIM(COALESCE(s.stage1_why_it_matters_ux_description, '')), '') AS stage1_why_it_matters_ux_description,
  NULLIF(TRIM(COALESCE(s.audience_lens, '')), '') AS audience_lens
FROM (
  SELECT
    s.*,
    ROW_NUMBER() OVER (
      PARTITION BY s.stage1_wrapper_ux_slug
      ORDER BY s.min_months ASC, s.age_band_id ASC, s.stage1_wrapper_rank_in_band ASC
    ) AS rn
  FROM tmp_discover_projection_stage s
) s
WHERE s.rn = 1;

CREATE TEMP TABLE tmp_discover_stage1_age_band_wrappers AS
SELECT
  s.age_band_id,
  s.stage1_wrapper_ux_slug,
  MIN(s.stage1_wrapper_rank_in_band) AS stage1_wrapper_rank_in_band,
  BOOL_OR(s.stage1_mapping_is_active) AS stage1_mapping_is_active
FROM tmp_discover_projection_stage s
GROUP BY s.age_band_id, s.stage1_wrapper_ux_slug;

CREATE TEMP TABLE tmp_discover_stage1_wrapper_needs AS
SELECT
  s.stage1_wrapper_ux_slug,
  s.development_need_slug,
  s.development_need_canonical_name
FROM (
  SELECT
    s.*,
    ROW_NUMBER() OVER (
      PARTITION BY s.stage1_wrapper_ux_slug
      ORDER BY s.stage2_play_ideas_rank ASC, s.min_months ASC, s.age_band_id ASC
    ) AS rn
  FROM tmp_discover_projection_stage s
) s
WHERE s.rn = 1;

CREATE TEMP TABLE tmp_discover_stage2_category_types AS
SELECT
  s.stage2_category_type_slug,
  s.stage2_category_type_name
FROM (
  SELECT
    s.*,
    ROW_NUMBER() OVER (
      PARTITION BY LOWER(TRIM(s.stage2_category_type_slug))
      ORDER BY s.min_months ASC, s.age_band_id ASC, s.stage2_play_ideas_rank ASC
    ) AS rn
  FROM tmp_discover_projection_stage s
) s
WHERE s.rn = 1;

INSERT INTO public.pl_age_bands (id, label, min_months, max_months, is_active)
SELECT DISTINCT
  s.age_band_id,
  s.age_band_label,
  s.min_months,
  s.max_months,
  s.age_band_is_active
FROM tmp_discover_projection_stage s
ON CONFLICT (id) DO UPDATE
SET
  label = EXCLUDED.label,
  min_months = EXCLUDED.min_months,
  max_months = EXCLUDED.max_months,
  is_active = EXCLUDED.is_active,
  updated_at = now();

INSERT INTO public.pl_development_needs (
  name,
  slug,
  plain_english_description,
  why_it_matters
)
SELECT
  src.development_need_canonical_name,
  src.development_need_slug,
  COALESCE(src.stage1_why_it_matters_ux_description, ''),
  COALESCE(src.stage1_why_it_matters_ux_description, '')
FROM (
  SELECT DISTINCT
    s.development_need_slug,
    s.development_need_canonical_name,
    NULLIF(TRIM(COALESCE(s.stage1_why_it_matters_ux_description, '')), '') AS stage1_why_it_matters_ux_description
  FROM tmp_discover_projection_stage s
) src
LEFT JOIN public.pl_development_needs dn_slug
  ON LOWER(COALESCE(dn_slug.slug, '')) = LOWER(src.development_need_slug)
LEFT JOIN public.pl_development_needs dn_name
  ON LOWER(COALESCE(dn_name.name, '')) = LOWER(src.development_need_canonical_name)
WHERE dn_slug.id IS NULL
  AND dn_name.id IS NULL
ON CONFLICT (slug) DO NOTHING;

UPDATE public.pl_development_needs dn
SET
  name = src.development_need_canonical_name,
  plain_english_description = COALESCE(src.stage1_why_it_matters_ux_description, ''),
  why_it_matters = COALESCE(src.stage1_why_it_matters_ux_description, ''),
  updated_at = now()
FROM (
  SELECT DISTINCT
    s.development_need_slug,
    s.development_need_canonical_name,
    NULLIF(TRIM(COALESCE(s.stage1_why_it_matters_ux_description, '')), '') AS stage1_why_it_matters_ux_description
  FROM tmp_discover_projection_stage s
) src
WHERE LOWER(COALESCE(dn.slug, '')) = LOWER(src.development_need_slug);

INSERT INTO public.pl_ux_wrappers (
  ux_slug,
  ux_label,
  ux_description,
  audience_lens,
  is_active
)
SELECT
  s.stage1_wrapper_ux_slug,
  s.stage1_wrapper_ux_label,
  s.stage1_why_it_matters_ux_description,
  s.audience_lens,
  true
FROM tmp_discover_stage1_wrappers s
ON CONFLICT (ux_slug) DO UPDATE
SET
  ux_label = EXCLUDED.ux_label,
  ux_description = EXCLUDED.ux_description,
  audience_lens = EXCLUDED.audience_lens,
  is_active = true,
  updated_at = now();

INSERT INTO public.pl_ux_wrapper_needs (
  ux_wrapper_id,
  development_need_id
)
SELECT
  uw.id AS ux_wrapper_id,
  dn.id AS development_need_id
FROM tmp_discover_stage1_wrapper_needs s
JOIN public.pl_ux_wrappers uw
  ON LOWER(uw.ux_slug) = LOWER(s.stage1_wrapper_ux_slug)
JOIN LATERAL (
  SELECT d.id
  FROM public.pl_development_needs d
  WHERE LOWER(COALESCE(d.slug, '')) = LOWER(s.development_need_slug)
     OR LOWER(COALESCE(d.name, '')) = LOWER(s.development_need_canonical_name)
  ORDER BY
    CASE WHEN LOWER(COALESCE(d.slug, '')) = LOWER(s.development_need_slug) THEN 0 ELSE 1 END,
    d.id
  LIMIT 1
) dn ON true
ON CONFLICT (ux_wrapper_id) DO UPDATE
SET
  development_need_id = EXCLUDED.development_need_id,
  updated_at = now();

UPDATE public.pl_age_band_ux_wrappers abuw
SET
  is_active = false,
  updated_at = now()
WHERE abuw.age_band_id IN (SELECT DISTINCT age_band_id FROM tmp_discover_stage1_age_band_wrappers)
  AND NOT EXISTS (
    SELECT 1
    FROM tmp_discover_stage1_age_band_wrappers s
    JOIN public.pl_ux_wrappers uw ON LOWER(uw.ux_slug) = LOWER(s.stage1_wrapper_ux_slug)
    WHERE s.age_band_id = abuw.age_band_id
      AND uw.id = abuw.ux_wrapper_id
  );

INSERT INTO public.pl_age_band_ux_wrappers (
  age_band_id,
  ux_wrapper_id,
  rank,
  is_active
)
SELECT
  s.age_band_id,
  uw.id,
  s.stage1_wrapper_rank_in_band,
  s.stage1_mapping_is_active
FROM tmp_discover_stage1_age_band_wrappers s
JOIN public.pl_ux_wrappers uw
  ON LOWER(uw.ux_slug) = LOWER(s.stage1_wrapper_ux_slug)
ON CONFLICT (age_band_id, ux_wrapper_id) DO UPDATE
SET
  rank = EXCLUDED.rank,
  is_active = EXCLUDED.is_active,
  updated_at = now();

INSERT INTO public.pl_category_types (
  slug,
  label,
  name,
  description,
  safety_notes
)
SELECT
  src.stage2_category_type_slug,
  src.stage2_category_type_name,
  src.stage2_category_type_name,
  NULL,
  NULL
FROM tmp_discover_stage2_category_types src
LEFT JOIN public.pl_category_types ct_slug
  ON LOWER(COALESCE(ct_slug.slug, '')) = LOWER(src.stage2_category_type_slug)
WHERE ct_slug.id IS NULL
ON CONFLICT (slug) DO NOTHING;

CREATE TEMP TABLE tmp_discover_resolved_need_category AS
SELECT DISTINCT
  s.age_band_id,
  dn.id AS development_need_id,
  ct.id AS category_type_id,
  s.stage2_play_ideas_rank AS rank,
  NULLIF(TRIM(COALESCE(s.stage2_play_idea_mapping_rationale, '')), '') AS rationale,
  NULLIF(TRIM(COALESCE(s.stage2_category_type_label, '')), '') AS display_label,
  NULLIF(TRIM(COALESCE(s.category_audience_lens, '')), '') AS audience_lens
FROM tmp_discover_projection_stage s
JOIN LATERAL (
  SELECT d.id
  FROM public.pl_development_needs d
  WHERE LOWER(COALESCE(d.slug, '')) = LOWER(s.development_need_slug)
     OR LOWER(COALESCE(d.name, '')) = LOWER(s.development_need_canonical_name)
  ORDER BY
    CASE WHEN LOWER(COALESCE(d.slug, '')) = LOWER(s.development_need_slug) THEN 0 ELSE 1 END,
    d.id
  LIMIT 1
) dn ON true
JOIN LATERAL (
  SELECT c.id
  FROM public.pl_category_types c
  WHERE LOWER(COALESCE(c.slug, '')) = LOWER(s.stage2_category_type_slug)
     OR LOWER(COALESCE(c.name, '')) = LOWER(s.stage2_category_type_name)
     OR LOWER(COALESCE(c.label, '')) = LOWER(s.stage2_category_type_label)
  ORDER BY
    CASE
      WHEN LOWER(COALESCE(c.slug, '')) = LOWER(s.stage2_category_type_slug) THEN 0
      WHEN LOWER(COALESCE(c.name, '')) = LOWER(s.stage2_category_type_name) THEN 1
      ELSE 2
    END,
    c.id
  LIMIT 1
) ct ON true;

UPDATE public.pl_age_band_development_need_category_types m
SET
  is_active = false,
  updated_at = now()
WHERE m.age_band_id IN (SELECT DISTINCT age_band_id FROM tmp_discover_projection_stage)
  AND NOT EXISTS (
    SELECT 1
    FROM tmp_discover_resolved_need_category r
    WHERE r.age_band_id = m.age_band_id
      AND r.development_need_id = m.development_need_id
      AND r.category_type_id = m.category_type_id
  );

INSERT INTO public.pl_age_band_development_need_category_types (
  age_band_id,
  development_need_id,
  category_type_id,
  rank,
  rationale,
  display_label,
  audience_lens,
  is_active
)
SELECT
  r.age_band_id,
  r.development_need_id,
  r.category_type_id,
  r.rank,
  r.rationale,
  r.display_label,
  r.audience_lens,
  true
FROM tmp_discover_resolved_need_category r
ON CONFLICT (age_band_id, development_need_id, category_type_id) DO UPDATE
SET
  rank = EXCLUDED.rank,
  rationale = EXCLUDED.rationale,
  display_label = EXCLUDED.display_label,
  audience_lens = EXCLUDED.audience_lens,
  is_active = true,
  updated_at = now();

UPDATE public.pl_age_band_category_type_products p
SET
  is_active = false,
  updated_at = now()
WHERE p.age_band_id IN (SELECT DISTINCT age_band_id FROM tmp_discover_projection_stage);

DO $$
DECLARE
  v_rows_loaded INTEGER;
  v_rows_19_21m INTEGER;
  v_clusters_19_21m INTEGER;
  v_rows_25_27m INTEGER;
  v_clusters_25_27m INTEGER;
  v_rows_31_33m INTEGER;
  v_clusters_31_33m INTEGER;
  v_stage3_active INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_rows_loaded FROM tmp_discover_projection_stage;
  SELECT COUNT(*) INTO v_rows_19_21m FROM tmp_discover_projection_stage WHERE age_band_id = '19-21m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_19_21m
  FROM tmp_discover_projection_stage WHERE age_band_id = '19-21m';
  SELECT COUNT(*) INTO v_rows_25_27m FROM tmp_discover_projection_stage WHERE age_band_id = '25-27m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_25_27m
  FROM tmp_discover_projection_stage WHERE age_band_id = '25-27m';
  SELECT COUNT(*) INTO v_rows_31_33m FROM tmp_discover_projection_stage WHERE age_band_id = '31-33m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_31_33m
  FROM tmp_discover_projection_stage WHERE age_band_id = '31-33m';
  SELECT COUNT(*) INTO v_stage3_active
  FROM public.pl_age_band_category_type_products
  WHERE age_band_id IN ('19-21m', '25-27m', '31-33m')
    AND is_active = true;

  RAISE NOTICE 'Discover projection rows loaded: % (expected 120)', v_rows_loaded;
  RAISE NOTICE '19-21m rows: % (expected 39), clusters: % (expected 8)', v_rows_19_21m, v_clusters_19_21m;
  RAISE NOTICE '25-27m rows: % (expected 41), clusters: % (expected 8)', v_rows_25_27m, v_clusters_25_27m;
  RAISE NOTICE '31-33m rows: % (expected 40), clusters: % (expected 8)', v_rows_31_33m, v_clusters_31_33m;
  RAISE NOTICE 'Active Stage 3 mappings (expected 0): %', v_stage3_active;

  IF v_rows_loaded <> 120 THEN
    RAISE EXCEPTION 'Row count validation failed';
  END IF;
  IF v_rows_19_21m <> 39 THEN
    RAISE EXCEPTION 'Row count validation failed for 19-21m';
  END IF;
  IF v_rows_25_27m <> 41 THEN
    RAISE EXCEPTION 'Row count validation failed for 25-27m';
  END IF;
  IF v_rows_31_33m <> 40 THEN
    RAISE EXCEPTION 'Row count validation failed for 31-33m';
  END IF;
  IF v_clusters_19_21m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 19-21m';
  END IF;
  IF v_clusters_25_27m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 25-27m';
  END IF;
  IF v_clusters_31_33m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 31-33m';
  END IF;
END $$;

COMMIT;

